SELECT count(*) FROM name, cast_info, role_type, aka_name, title, char_name, kind_type WHERE cast_info.person_id = name.id AND cast_info.role_id = role_type.id AND aka_name.person_id = name.id AND cast_info.movie_id = title.id AND cast_info.person_role_id = char_name.id AND title.kind_id = kind_type.id;